define("theme_boost_union/focusededit",["core/str"],(function(Str){"use strict";const STORAGE_KEY="theme_boost_union-editing-focused",FOCUSED_CLASS="theme-editing-focused";const getStoredPreference=function(){try{const value=window.localStorage.getItem(STORAGE_KEY);if("1"===value){return!0}if("0"===value){return!1}}catch(e){return null}return null};const storePreference=function(focused){try{window.localStorage.setItem(STORAGE_KEY,focused?"1":"0")}catch(e){return}};const updateButton=function(button,focused){button.setAttribute("aria-pressed",focused?"false":"true");button.classList.toggle("active",!focused)};const init=function(){const body=document.body,editswitch=document.querySelector(".editmode-switch-form");if(!editswitch){return}const stored=getStoredPreference();if(null!==stored){body.classList.toggle(FOCUSED_CLASS,stored)}const button=document.createElement("button");button.type="button";button.className="btn theme-focusededit-toggle";button.innerHTML='<i class="fa-solid fa-table-cells-large" aria-hidden="true"></i>';updateButton(button,body.classList.contains(FOCUSED_CLASS));Str.get_strings([{key:"editingfocustoggle",component:"theme_boost_union"},{key:"editingfocustoggle_desc",component:"theme_boost_union"}]).then((function(strings){button.setAttribute("title",strings[1]);const sr=document.createElement("span");sr.className="visually-hidden";sr.textContent=strings[0];button.appendChild(sr);return strings})).catch((function(){return}));button.addEventListener("click",(function(){const focused=!body.classList.contains(FOCUSED_CLASS);body.classList.toggle(FOCUSED_CLASS,focused);updateButton(button,focused);storePreference(focused)}));editswitch.insertAdjacentElement("afterend",button)};return{init:init}}));
